class AISummarizer {
  constructor(apiKey, model = 'claude-3-haiku-20240307') {
    this.apiKey = apiKey;
    this.model = model;
    this.baseUrl = 'https://api.anthropic.com/v1/messages';
  }

  async summarize(text, maxLength = 200) {
    // Validate input
    if (!text || text.length < 50) {
      return 'Note too short to summarize effectively.';
    }

    if (text.length > 100000) {
      // Truncate to avoid token limits (rough estimate: 4 chars per token)
      text = text.substring(0, 100000);
    }

    const prompt = `You are a knowledge synthesis assistant. Your task is to create a concise, informative summary of the following note.

REQUIREMENTS:
- Summary length: ${maxLength} characters maximum
- Capture the main idea and key points
- Use bullet points for multiple concepts
- Preserve any specific data, names, or references
- If the note contains action items, include them
- Use neutral, professional language

FORMAT YOUR RESPONSE AS:
## Summary
[Brief summary paragraph]

## Key Points
- [Point 1]
- [Point 2]

## Action Items (if any)
- [Action item]

NOTE TO SUMMARIZE:
${text}

SUMMARY:`;

    try {
      const response = await fetch(this.baseUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': this.apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-password-access': 'true'
        },
        body: JSON.stringify({
          model: this.model,
          max_tokens: 500,
          messages: [
            {
              role: 'user',
              content: prompt
            }
          ]
        })
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(`API Error ${response.status}: ${errorData.error?.message || response.statusText}`);
      }

      const data = await response.json();
      // Claude returns content as an array of blocks
      const summaryText = data.content[0].text;
      return summaryText;

    } catch (error) {
      console.error('Summarization failed:', error);
      throw new Error(`Failed to generate summary: ${error.message}`);
    }
  }

  async expandNote(summary) {
    // Inverse operation: take a summary and expand it with likely details
    const prompt = `Expand this summary into a detailed note. Generate realistic, plausible content that fits the context.

If you're unsure about specific details, use placeholder brackets like [specific detail] to indicate where user input is needed.

SUMMARY:
${summary}


EXPANDED NOTE:`;

    try {
