`,  
  // Custom formatting functions
  slugify: (text) => {
    return text
      .toLowerCase()
      .trim()
      .replace(/[^\w\s-]/g, '')
      .replace(/[\s_-]+/g, '-')
      .replace(/^-+|-+$/g, '');
  },

  // Validation before creation
  validate: (input) => {
    if (input.length < 3) {
      return "Project name must be at least 3 characters";
    }
    if (input.length > 100) {
      return "Project name is too long (max 100 characters)";
    }
    return true;
  },

  // Post-creation hook
  after: (note) => {
    // Open the newly created note
    app.workspace.getLeaf(false).openFile(note);

    // Log creation for audit purposes
    console.log(`Created project note: ${note.basename}`);
  }
};

// Execute the template
module.exports = async (params) => {
  const { quickAddApi } = app.plugins.plugins.quickadd;

  // Capture user input
  const projectName = await quickAddApi.inputPrompt(
    "Project Name:",
    "my-awesome-project"
  );

  // Validate input
  const validation = projectTemplate.validate(projectName);
  if (validation !== true) {
    new Notice(validation);
    return;
  }

  // Generate slug for filename
  const projectSlug = projectTemplate.slugify(projectName);
  const fileName = `Project-${projectSlug}.md`;

  // Determine file path
  const filePath = `01-Projects/${fileName}`;

  // Check for existing file
  if (app.vault.getAbstractFileByPath(filePath)) {
    new Notice(`Project note already exists: ${fileName}`);
    return;
  }

  // Create the file with processed template
  const templateContent = projectTemplate.template
    .replace(/\{\{project_name\}\}/g, projectName)
    .replace(/\{\{project_slug\}\}/g, projectSlug)
    .replace(/\{\{area_slug\}\}/g, "general");

  await app.vault.create(filePath, templateContent);

  // Run post-creation hook
  const newFile = app.vault.getAbstractFileByPath(filePath);
  projectTemplate.after(newFile);
};

