```python
// ========================================
// Simple RAG Pipeline: Vault Query System
// Combines semantic search with AI for conversational retrieval
// ========================================

class VaultRAG {
  constructor(embeddingsApi, chatApi, app) {
    this.embeddingsApi = embeddingsApi;
    this.chatApi = chatApi;
    this.app = app;
    this.chunkSize = 1000; // characters
    this.chunkOverlap = 200; // characters
    this.maxResults = 5;
  }

  // Split text into overlapping chunks for embedding
  chunkText(text) {
    const chunks = [];
    for (let i = 0; i < text.length; i += this.chunkSize - this.chunkOverlap) {
      const chunk = text.substring(i, i + this.chunkSize);
      chunks.push({
        text: chunk,
        index: i
      });
    }
    return chunks;
  }

  // Get embedding for text (using OpenAI as example)
  async getEmbedding(text, apiKey) {
    const response = await fetch('https://api.openai.com/v1/embeddings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: 'text-embedding-3-small',
        input: text
      })
    });

    const data = await response.json();
    return data.data[0].embedding;
  }

  // Cosine similarity between two vectors
  cosineSimilarity(a, b) {
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;

    for (let i = 0; i < a.length; i++) {
      dotProduct += a[i] * b[i];
      normA += a[i] * a[i];
      normB += b[i] * b[i];
    }

    normA = Math.sqrt(normA);
    normB = Math.sqrt(normB);

    return dotProduct / (normA * normB);
  }

  // Search vault files (simple keyword + content search)
  async searchVaultFiles(query, maxFiles = 50) {
    const files = this.app.vault.getFiles()
      .filter(f => f.extension === 'md')
      .filter(f => !f.path.startsWith('.obsidian')) // Exclude config
      .filter(f => !f.path.includes('.trash')); // Exclude trash

    const results = [];

    for (const file of files.slice(0, maxFiles)) {
      try {
        const content = await this.app.vault.read(file);
        const text = `${file.basename}\n${content}`;

        results.push({
          path: file.path,
          basename: file.basename,
          content: content,
          text: text
        });
      } catch (e) {
        console.warn(`Could not read ${file.path}:`, e);
      }
    }

    return results;
  }

  // Main RAG query function
  async query(query, apiKey, conversationHistory = []) {
    // Step 1: Get embedding for the query
    console.log('Generating query embedding...');
    const queryEmbedding = await this.getEmbedding(query, apiKey);

    // Step 2: Search and score all notes
    console.log('Searching vault...');
    const files = await this.searchVaultFiles(query);

    const scoredFiles = [];

    for (const file of files) {
      try {
        // Chunk the file content
        const chunks = this.chunkText(file.content);

        // Score each chunk
        for (const chunk of chunks) {
          const chunkEmbedding = await this.getEmbedding(chunk.text, apiKey);
          const similarity = this.cosineSimilarity(queryEmbedding, chunkEmbedding);

          scoredFiles.push({
            ...file,
            chunk: chunk.text,
            similarity: similarity
          });
        }
      } catch (e) {
        console.warn(`Error processing ${file.path}:`, e);
      }
    }

    // Step 3: Get top relevant chunks
    const topChunks = scoredFiles
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, this.maxResults);

    console.log(`Found ${topChunks.length} relevant chunks`);

    // Step 4: Build context from retrieved chunks
    const context = topChunks.map((item, idx) => 
      `[${idx + 1}] Source: ${item.basename}\n${item.chunk.substring(0, 500)}...`
    ).join('\n\n---\n\n');

    // Step 5: Generate response with retrieved context
    const systemPrompt = `You are a helpful assistant answering questions about the user's personal knowledge base (Second Brain).

INSTRUCTIONS:
- Answer based ONLY on the provided context from the user's notes
- If the context doesn't contain relevant information, say "I couldn't find relevant notes in your vault for this query."
- Cite specific sources using the [number] format
- Be specific and reference actual content from the notes
- If you're inferring or extrapolating, clearly state this

VAULT CONTEXT:
${context}`;

    const messages = [
      { role: 'system', content: systemPrompt },
      ...conversationHistory.slice(-4), // Keep last 4 messages for context
      { role: 'user', content: query }
    ];

    // Step 6: Call chat API
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: messages,
        max_tokens: 1000,
        temperature: 0.3 // Lower temp for more factual responses
      })
    });

    const data = await response.json();
    const answer = data.choices[0].message.content;

    return {
      answer: answer,
      sources: topChunks.map((item, idx) => ({
        rank: idx + 1,
        file: item.basename,
        path: item.path,
        relevance: Math.round(item.similarity * 100) + '%'
      })),
      conversationHistory: [
        ...conversationHistory,
        { role: 'user', content: query },
        { role: 'assistant', content: answer }
      ]
    };
  }
}

